+            } else {
+                try self.writeByte(@intFromEnum(Opcode.TUPLE));
+            }
+        }
+
+        /// Tuple with 2 elements
+        pub fn dumpTuple2(self: *Self) !void {
+            if (protocol >= 2) {
+                try self.writeByte(@intFromEnum(Opcode.TUPLE2));
+            } else {
+                try self.writeByte(@intFromEnum(Opcode.TUPLE));
+            }
+        }
+
+        /// Tuple with 3 elements
+        pub fn dumpTuple3(self: *Self) !void {
+            if (protocol >= 2) {
