+            return -@log(1.0 - self.random()) * beta;
+        } else {
+            // alpha < 1
+            var x: f64 = undefined;
+            while (true) {
+                const u = self.random();
+                const b = (std.math.e + alpha) / std.math.e;
+                const p = b * u;
