+    }
+
+    /// Shuffle sequence in place
+    pub fn shuffle(self: *Self, comptime T: type, seq: []T) void {
+        var i: usize = seq.len;
+        while (i > 1) {
+            i -= 1;
+            const j = self.randrange(i + 1);
+            const tmp = seq[i];
+            seq[i] = seq[@intCast(j)];
+            seq[@intCast(j)] = tmp;
+        }
+    }
